import type { IndicatorResponse } from './types'

const API_URL = process.env.NEXT_PUBLIC_API_URL ?? 'http://localhost:8000'

async function get<T>(path: string, params: Record<string, string> = {}): Promise<T> {
  const isServer = typeof window === 'undefined'

  let fetchUrl: string
  if (isServer) {
    const url = new URL(path, API_URL)
    Object.entries(params).forEach(([k, v]) => {
      if (v !== undefined && v !== '') url.searchParams.set(k, v)
    })
    fetchUrl = url.toString()
  } else {
    const url = new URL(`/api${path}`, window.location.origin)
    Object.entries(params).forEach(([k, v]) => {
      if (v !== undefined && v !== '') url.searchParams.set(k, v)
    })
    fetchUrl = url.toString()
  }

  const res = await fetch(fetchUrl)
  if (!res.ok) {
    const err = await res.json().catch(() => ({ detail: res.statusText }))
    throw new Error(err.detail || `API error ${res.status}`)
  }
  return res.json()
}

export function fetchIndicator(
  path: string,
  params: Record<string, string> = {}
): Promise<IndicatorResponse> {
  return get<IndicatorResponse>(path, params)
}

export async function fetchAllProvinces(
  path: string,
  params: Record<string, string> = {}
): Promise<IndicatorResponse[]> {
  const codes = [1, 2, 3, 4, 5]
  return Promise.all(
    codes.map((code) => fetchIndicator(path, { ...params, region: String(code) }))
  )
}

import type { NextConfig } from 'next'

const replitDomain = process.env.REPLIT_DEV_DOMAIN
const replitDomains = process.env.REPLIT_DOMAINS
const apiUrl = process.env.NEXT_PUBLIC_API_URL ?? 'http://localhost:8000'

const allowedOrigins: string[] = []
if (replitDomain) allowedOrigins.push(replitDomain)
if (replitDomains) {
  replitDomains.split(',').forEach((d) => allowedOrigins.push(d.trim()))
}

const nextConfig: NextConfig = {
  async rewrites() {
    return [
      {
        source: '/api/:path*',
        destination: `${apiUrl}/:path*`,
      },
    ]
  },
  allowedDevOrigins: allowedOrigins.length > 0 ? allowedOrigins : undefined,
}

export default nextConfig

