const apiUrl = process.env.NEXT_PUBLIC_API_URL ?? 'http://localhost:8000/api'
const backendUrl = apiUrl.replace(/\/api$/, '')

const allowedOrigins: string[] = []
if (replitDomain) allowedOrigins.push(replitDomain)
if (replitDomains) {
  replitDomains.split(',').forEach((d) => allowedOrigins.push(d.trim()))
}

const nextConfig: NextConfig = {
  async rewrites() {
    return [
      {
        source: '/api/:path*',
        destination: `${backendUrl}/api/:path*`,
      },
      {
        source: '/admin-panel',
        destination: `${backendUrl}/admin-panel/`,
      },
      {
        source: '/admin-panel/:path*',
        destination: `${backendUrl}/admin-panel/:path*`,
      },
      {
        source: '/admin',
        destination: `${backendUrl}/admin/`,
      },
      {
        source: '/admin/:path*',
        destination: `${backendUrl}/admin/:path*`,
      },
    ]
  },
  allowedDevOrigins: allowedOrigins.length > 0 ? allowedOrigins : undefined,
}

export default nextConfig

